code.C:
#include <stdio.h>
int main() {
    long long balance = 1000;
    balance *= 2;   // Year 1
    balance *= 3;   // Year 2
    balance -= 500; // Withdrawal
    balance *= 2;   // Year 3
    printf("%lld\n", balance);
    return 0;
}

